INSERT INTO tbl_payment (
    payment_code, order_code, buyer_id, seller_id, work_id, auction_id,
    original_amount, total_price, total_fee,
    payment_purpose, pay_method, card_id, pg_receipt_id, status
) VALUES (
    #{paymentCode}, #{orderCode}, #{buyerId}, #{sellerId}, #{workId}, #{auctionId},
    #{originalAmount}, #{totalPrice}, #{totalFee},
    #{paymentPurpose}, #{payMethod}, #{cardId}, #{pgReceiptId}, #{status}
)

mapper.update:
UPDATE tbl_payment
SET status = 'COMPLETED', paid_at = NOW()
WHERE id = #{paymentId}

UPDATE tbl_payment
SET status = 'REFUNDED', refunded_at = NOW()
WHERE id = #{paymentId}

UPDATE tbl_payment
SET pg_receipt_id = #{pgReceiptId}
WHERE id = #{paymentId}

UPDATE tbl_payment
SET status = #{status}
WHERE buyer_id = #{buyerId}
  AND work_id = #{workId}
  AND status IN ('PENDING', 'AUTHORIZED')
  AND id != #{excludePaymentId}
